import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input to prevent XSS
        String sanitizedInput = sanitizeUserInput(userInput);
        String safeOutput = "<p>User Input: " + sanitizedInput + "</p>";

        PrintWriter out = response.getWriter();
        out.println(safeOutput);
    }

    private String sanitizeUserInput(String input) {
        // Implement proper input sanitization and encoding here
        // This can involve using a library like OWASP Java Encoder or ESAPI Encoder

        // Example: Using OWASP Java Encoder to encode HTML entities
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

